Absolutely! The `packed_simd` crate provides vector instructions. Here's a simple example summing elements with SIMD: 

```rust
use packed_simd::u8x16;

crate fn sum_vec_u8_simd(vec: &[u8]) -> u64 {
    let mut total = 0u64;
    for chunk in vec.chunks_exact(16) {
        let simdslice = u8x16::from_slice_unaligned(chunk);
        total += simdslice.sum() as u64;
    }
    total + vec.iter().skip(vec.len() / 16 * 16).map(|&x| x as u64).sum()
}
```
